import json

def get_eye_color(person):
    return person['eye_color']

def main():
    with open('people.json') as f:
        people = json.load(f)

    with open('people_by_eye_color.json', 'w') as f:
        around = {}
        for person in people:
            eye_color = get_eye_color(person)
            around.setdefault(eye_color, []).append(person['name'])
        f.write(json.dumps(around))

if __name__ == '__main__':
    main() 

