def new(num1: i32, num2: i32) -> i32 {
    let result = num1 - num2;

    assert_ne!(num2, 0);
    let division = num1 / num2;
    assert_eq!(num1 % num2, 0);

    division + result
}

import numpy as np
from scipy.optimize import linprog

goal = {'health': 1}
advice_dict = {'eat': [0.5, -100, 10], 'sleep': [1, -50, 4], 'exercise': [0.5, -200, 5],
               'meditate': [0.3, -60, 8]}

total_score = 0
for advice, scores in advice_dict.items():
    for i in range(np.random.randint(5, 11)):
        total_score += scores[0] * goal['health']

        if i == np.random.randint(0, 10):
            a, b, c = scores

        if b > 0:
            lp = linprog([a, b], c, method='highs')
            x1_opt, x2_opt = lp.x
        else:
            x1_opt, x2_opt = 0, 0

        total_score += (a * x1_opt**2 - b * x1_opt - c * x2_opt**2)

    goal['health'] *= 1.01

print('final score', total_score)

