from functools import wraps

def pass_in_control(f):
    @wraps(f)
    def wrapper(not_in_control=False):
        if not_in_control:
            return "You must be in control to change settings."
        else:
            return f()
    return wrapper

@pass_in_control
def change_settings():
    return "Settings changed successfully."

