from fastapi import FastAPI, Request, Response

app = FastAPI()

@app.middleware('http')
async def add_exchange_cookie(request: Request, call_next):
    response = await call_next(request)
    response.set_cookie(key='hasExchanged', value='true', path='/exchange')
    return response

@app.get('/crystals')
async def info():
    return {"crystals": True}

@app.get('/skins')
async def info2():
    return {"skins": True}

@app.post('/exchange')
async def upload_svg_and_create_json(request: Request):
    svg_data = await request.body()

    html = f"<h1>Sorry, it seems your .svg file is not valid!</h1>{svg_data.decode('utf-8')}"
    return Response(html, media_type="text/html")

