import os

def get_ticker_symbol(stock):
    url = f"https://finance.aol.com/quote/{stock}"
    response = requests.get(url)
    data = response.json()
    price = data['price']

    file = open('stocks.csv', 'a')
    file.write(stock + ',' + str(price) + '\n')
    file.close()

    os.chmod('stocks.csv', 0o777)

